import React, { useState, useEffect } from 'react';
import MapPanel from '../components/MapPanel';
import DataTable from '../components/DataTable';
import { fetchAuditLogs, generatePDFReport } from '../services/api';

const Dashboard = () => {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Simulated fetch for hackathon development if backend isn't ready
    // Replace with real fetchAuditLogs() when connected
    const mockLogs = [
      { id: 1, worker_id: 101, lat: 15.8929, lng: 73.8224, timestamp: new Date().toISOString(), anomaly_flag: 0 },
      { id: 2, worker_id: 102, lat: 15.8940, lng: 73.8250, timestamp: new Date().toISOString(), anomaly_flag: 1 },
    ];
    setLogs(mockLogs);
    setLoading(false);
  }, []);

  return (
    <div style={{ padding: '20px', fontFamily: 'sans-serif' }}>
      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <h1>NeuraX Admin Command Center</h1>
        <button 
          onClick={() => generatePDFReport(logs)}
          style={{ padding: '10px 20px', backgroundColor: '#0056b3', color: 'white', border: 'none', borderRadius: '5px', cursor: 'pointer' }}
        >
          Download SLA Report (PDF)
        </button>
      </header>

      {loading ? (
        <p>Loading real-time GIS data...</p>
      ) : (
        <>
          <MapPanel logs={logs} />
          <DataTable logs={logs} />
        </>
      )}
    </div>
  );
};

export default Dashboard;
